import { useState, useEffect } from "react";
import Navbar from "../../components/Navbar";
import RecipeCard from "../../components/RecipeCard";
import axios from "axios";

const API_BASE_URL = "http://localhost:8080/api";

export default function HomePage({ setPage, setSelectedRecipe }) {
  const [activeCategory, setActiveCategory] = useState("All Recipes");
  const [search, setSearch] = useState("");
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Available categories from the API
  const CATEGORIES = ["All Recipes", "Grilled", "Vegetarian", "Seafood", "Italian", "Asian"];

  useEffect(() => {
    fetchRecipes();
  }, []);

  const fetchRecipes = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_BASE_URL}/recipes`);
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching recipes:", err);
      setError("Failed to load recipes");
      // Fallback to empty array
      setRecipes([]);
    } finally {
      setLoading(false);
    }
  };

  const filtered = recipes.filter(r => {
    const matchCat = activeCategory === "All Recipes" || r.tag === activeCategory;
    const matchSearch = !search || r.title.toLowerCase().includes(search.toLowerCase()) ||
      (r.chefInfo && r.chefInfo.name && r.chefInfo.name.toLowerCase().includes(search.toLowerCase())) ||
      (r.tag && r.tag.toLowerCase().includes(search.toLowerCase()));
    return matchCat && matchSearch;
  });

  return (
    <div style={{ minHeight:"100vh", background:"#f5f4f0" }}>
      <Navbar setPage={setPage} />

      {/* Hero */}
      <section style={{ background:"linear-gradient(135deg,#1a1a2e 0%,#2d2d44 60%,#1a1a2e 100%)", textAlign:"center", padding:"72px 24px 80px", position:"relative", overflow:"hidden" }}>
        <div style={{ position:"absolute", inset:0, background:"radial-gradient(ellipse 70% 60% at 50% 50%,rgba(232,93,47,.12) 0%,transparent 70%)" }} />
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:"clamp(32px,5vw,52px)", fontWeight:900, color:"#fff", lineHeight:1.1, marginBottom:16, position:"relative" }}>
          Best recipes for your taste
        </h1>
        <p style={{ color:"#aab0c6", fontSize:15, maxWidth:420, margin:"0 auto 36px", lineHeight:1.6, fontWeight:300, position:"relative" }}>
          Discover delicious recipes from talented chefs around the world.
        </p>
        <div style={{ display:"flex", gap:14, justifyContent:"center", position:"relative" }}>
          <button className="btn-primary" style={{ width:"auto", padding:"13px 30px" }} onClick={() => setPage("signup")}>Get Started</button>
          <button style={{ background:"transparent", color:"#fff", border:"1.5px solid rgba(255,255,255,.35)", padding:"13px 30px", borderRadius:10, fontSize:14, fontWeight:500 }} onClick={() => setPage("login")}>Sign In</button>
        </div>
      </section>

      {/* Search */}
      <div style={{ background:"#fff", borderBottom:"1px solid #e8e6df", display:"flex", alignItems:"center", padding:"0 24px", height:52, gap:12 }}>
        <span style={{ color:"#bbb" }}>🔍</span>
        <input style={{ flex:1, border:"none", outline:"none", fontSize:14, color:"#333", background:"transparent" }}
          placeholder="Search recipes, chefs, or ingredients..." value={search} onChange={e => setSearch(e.target.value)} />
        <button style={{ background:"none", border:"none", color:"#555", fontSize:13, fontWeight:500 }}>≡ Filters</button>
      </div>

      {/* Main */}
      <main style={{ maxWidth:1100, margin:"0 auto", padding:"36px 24px 60px" }}>
        <p style={{ fontSize:11, fontWeight:600, color:"#999", letterSpacing:"1.2px", textTransform:"uppercase", marginBottom:12 }}>Categories</p>
        <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginBottom:36 }}>
          {CATEGORIES.map(cat => (
            <button key={cat} onClick={() => setActiveCategory(cat)} style={{
              display:"flex", alignItems:"center", gap:6, padding:"7px 16px", borderRadius:99,
              fontSize:13, fontWeight:500, border:"1.5px solid",
              borderColor: activeCategory === cat ? "#1a1a2e" : "transparent",
              background: activeCategory === cat ? "#1a1a2e" : "#fff",
              color: activeCategory === cat ? "#fff" : "#555",
              transition:"all .18s"
            }}>
              {CAT_DOTS[cat] && <span style={{ width:8, height:8, borderRadius:"50%", background:CAT_DOTS[cat], display:"inline-block" }} />}
              {cat}
            </button>
          ))}
        </div>

        <div style={{ display:"flex", alignItems:"baseline", gap:12, marginBottom:24 }}>
          <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:26, fontWeight:700, color:"#1a1a1a" }}>All Recipes</h2>
          <span style={{ fontSize:13, color:"#aaa" }}>
            {loading ? "Loading recipes..." : error ? error : `${filtered.length} recipes found`}
          </span>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "40px" }}>
            <div style={{ fontSize: "18px", color: "#666" }}>Loading recipes...</div>
          </div>
        ) : error ? (
          <div style={{ textAlign: "center", padding: "40px" }}>
            <div style={{ fontSize: "18px", color: "#e74c3c", marginBottom: "16px" }}>{error}</div>
            <button
              onClick={fetchRecipes}
              style={{
                padding: "10px 20px",
                background: "#1a1a2e",
                color: "#fff",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer"
              }}
            >
              Try Again
            </button>
          </div>
        ) : (
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(300px,1fr))", gap:24 }}>
            {filtered.map(recipe => (
              <RecipeCard
                key={recipe._id}
                recipe={{
                  ...recipe,
                  id: recipe._id,
                  chef: recipe.chefInfo ? recipe.chefInfo.name : "Unknown Chef"
                }}
                onClick={r => { setSelectedRecipe(r); setPage("recipe-detail"); }}
              />
            ))}
          </div>
        )}
      </main>

      {/* Footer */}
      <footer style={{ background:"#1a1a2e", padding:"48px 40px 24px" }}>
        <div style={{ maxWidth:1100, margin:"0 auto" }}>
          <div style={{ display:"grid", gridTemplateColumns:"2fr 1fr 1fr 1fr", gap:40, marginBottom:40 }}>
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:8, fontFamily:"'Playfair Display',serif", fontSize:18, color:"#fff", fontWeight:700, marginBottom:12 }}>
                <div style={{ width:22, height:22, background:"linear-gradient(135deg,#e85d2f,#c0392b)", borderRadius:5, display:"flex", alignItems:"center", justifyContent:"center", fontSize:12 }}>🍽</div>
                RecipeNest
              </div>
              <p style={{ fontSize:13, color:"#6b7290", lineHeight:1.6, fontWeight:300, maxWidth:220 }}>Connecting food lovers with exceptional recipes from the world's most talented chefs.</p>
            </div>
            {[["Platform",["Explore","Categories","Trending"]],["Company",["About Us","Careers","Contact"]],["Legal",["Privacy Policy","Terms"]]].map(([title, links]) => (
              <div key={title}>
                <p style={{ fontSize:11, fontWeight:700, color:"#fff", letterSpacing:1, textTransform:"uppercase", marginBottom:14 }}>{title}</p>
                {links.map(l => <button key={l} style={{ display:"block", fontSize:13, color:"#6b7290", marginBottom:8, background:"none", border:"none", textAlign:"left" }}>{l}</button>)}
              </div>
            ))}
          </div>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", borderTop:"1px solid rgba(255,255,255,.08)", paddingTop:20 }}>
            <span style={{ fontSize:12, color:"#4a5068" }}>© 2024 RecipeNest. All rights reserved.</span>
            <div style={{ display:"flex", gap:10 }}>
              {["📸","🐦","💼"].map(s => (
                <button key={s} style={{ background:"rgba(255,255,255,.07)", border:"none", color:"#aab0c6", width:32, height:32, borderRadius:8, fontSize:14 }}>{s}</button>
              ))}
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
